SELECT ?decade ?data_type ?data_typeLabel
       ?research_paradigm ?research_paradigmLabel
       ?method_type ?method_typeLabel
       ?paper_count
WHERE {
    {
        SELECT ?decade ?data_type ?data_typeLabel (MAX(?paper_count) AS ?max_paper_count)
        WHERE {
            {
                SELECT ?decade ?data_type ?data_typeLabel
                       ?research_paradigm ?research_paradigmLabel
                       ?method_type ?method_typeLabel
                       (COUNT(DISTINCT ?paper) AS ?paper_count)
                WHERE {
                    ?paper pgmr:has_contribution ?contribution ;
                           pgmr:publication_year ?year .

                    ?contribution a pgmrc:empirical_research_practice_contribution ;
                                  pgmr:venue_serie ?venue ;
                                  pgmr:research_paradigm ?research_paradigm ;
                                  pgmr:data_collection ?data_collection .

                    ?venue rdfs:label ?venue_name .

                    ?research_paradigm rdfs:label ?research_paradigmLabel .

                    ?data_collection rdfs:label ?dc_label ;
                                     pgmr:data ?research_data ;
                                     pgmr:method ?dc_method .

                    ?research_data pgmr:data_type ?data_type .
                    ?data_type rdfs:label ?data_typeLabel .

                    ?dc_method pgmr:method_type ?method_type .
                    ?method_type rdfs:label ?method_typeLabel .

                    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
                    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

                    FILTER(?dc_label != "no collection"^^xsd:string)
                    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
                    FILTER(
                        ?data_typeLabel = "qualitative"^^xsd:string ||
                        ?data_typeLabel = "quantitative"^^xsd:string
                    )
                }
                GROUP BY ?decade ?data_type ?data_typeLabel
                         ?research_paradigm ?research_paradigmLabel
                         ?method_type ?method_typeLabel
            }
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
    }

    {
        SELECT ?decade ?data_type ?data_typeLabel
               ?research_paradigm ?research_paradigmLabel
               ?method_type ?method_typeLabel
               (COUNT(DISTINCT ?paper) AS ?paper_count)
        WHERE {
            ?paper pgmr:has_contribution ?contribution ;
                   pgmr:publication_year ?year .

            ?contribution a pgmrc:empirical_research_practice_contribution ;
                          pgmr:venue_serie ?venue ;
                          pgmr:research_paradigm ?research_paradigm ;
                          pgmr:data_collection ?data_collection .

            ?venue rdfs:label ?venue_name .

            ?research_paradigm rdfs:label ?research_paradigmLabel .

            ?data_collection rdfs:label ?dc_label ;
                             pgmr:data ?research_data ;
                             pgmr:method ?dc_method .

            ?research_data pgmr:data_type ?data_type .
            ?data_type rdfs:label ?data_typeLabel .

            ?dc_method pgmr:method_type ?method_type .
            ?method_type rdfs:label ?method_typeLabel .

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
            BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

            FILTER(?dc_label != "no collection"^^xsd:string)
            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
            FILTER(
                ?data_typeLabel = "qualitative"^^xsd:string ||
                ?data_typeLabel = "quantitative"^^xsd:string
            )
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
                 ?research_paradigm ?research_paradigmLabel
                 ?method_type ?method_typeLabel
    }

    FILTER(?paper_count = ?max_paper_count)
}
ORDER BY ?decade ?data_typeLabel DESC(?paper_count) ?research_paradigmLabel ?method_typeLabel

SELECT ?inferential_statistics_group
       ?ml_algorithm
       ?ml_algorithmLabel
       ?metric_value
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT DISTINCT ?paper ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
        WHERE {
            ?paper pgmr:has_contribution ?contribution .

            OPTIONAL { ?paper rdfs:label ?paperLabel . }

            ?contribution a pgmrc:empirical_research_practice_contribution ;
                          pgmr:venue_serie ?venue ;
                          pgmr:data_analysis ?data_analysis .

            ?venue rdfs:label ?venue_name .

            ?data_analysis rdfs:label ?da_label .

            ?data_analysis pgmr:machine_learning ?machine_learning .

            ?machine_learning pgmr:algorithm ?ml_algorithm .

            OPTIONAL { ?ml_algorithm rdfs:label ?ml_algorithmLabel . }

            ?machine_learning pgmr:metric ?metric .

            {
                ?metric pgmr:recall ?recall .
                BIND("recall"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric pgmr:precision ?precision .
                BIND("precision"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric pgmr:accuracy ?accuracy .
                BIND("accuracy"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric pgmr:f_score ?f_score .
                BIND("f-score"^^xsd:string AS ?metric_value)
            }

            BIND(
                IF(
                    EXISTS {
                        ?data_analysis pgmr:inferential_statistics ?inferential_statistics .
                    },
                    "with inferential statistics"^^xsd:string,
                    "without inferential statistics"^^xsd:string
                ) AS ?inferential_statistics_group
            )

            FILTER(?da_label != "no analysis"^^xsd:string)

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
    }
}

GROUP BY ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
ORDER BY ?inferential_statistics_group DESC(?paper_count) ?ml_algorithmLabel ?metric_value

SELECT ?year
       (SUM(?has_both_highlighted) AS ?papers_with_both_highlighted)
       (SUM(?has_both_highlighted_and_data_url_and_threats_mentioned) AS ?papers_with_both_highlighted_and_also_data_url_and_threats_mentioned)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?both_highlighted_flag) AS ?has_both_highlighted)
               (MAX(?all_conditions_flag) AS ?has_both_highlighted_and_data_url_and_threats_mentioned)
        WHERE {
            ?paper pgmr:has_contribution ?contribution ;
                   pgmr:publication_year ?year .

            ?contribution a pgmrc:empirical_research_practice_contribution ;
                          pgmr:venue_serie ?venue .

            ?venue rdfs:label ?venue_name .

            ?contribution pgmr:research_question ?research_question .
            ?research_question pgmr:highlighted_in_text ?rq_highlighted .

            ?contribution pgmr:research_question_answer ?research_question_answer .
            ?research_question_answer pgmr:highlighted_in_text ?rqa_highlighted .

            BIND(1 AS ?both_highlighted_flag)

            OPTIONAL {
                ?contribution pgmr:data_collection ?data_collection ;
                              pgmr:threat_to_validity ?threats .

                ?data_collection rdfs:label ?dc_label ;
                                 pgmr:data ?research_data .

                ?research_data pgmr:url ?url .
                ?threats pgmr:mentioned ?mentioned .

                FILTER(?dc_label != "no collection"^^xsd:string)

                BIND(1 AS ?all_conditions_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT ?year ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?rq_flag) AS ?has_rq)
               (MAX(?rqa_flag) AS ?has_rqa)
        WHERE {
            ?paper pgmr:has_contribution ?contribution ;
                   pgmr:publication_year ?year .

            ?contribution a pgmrc:empirical_research_practice_contribution ;
                          pgmr:venue_serie ?venue .

            ?venue rdfs:label ?venue_name .

            OPTIONAL {
                ?contribution pgmr:research_question ?research_question .
                BIND(1 AS ?rq_flag)
            }

            OPTIONAL {
                ?contribution pgmr:research_question_answer ?research_question_answer .
                BIND(1 AS ?rqa_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }

    BIND(
        IF(?has_rq = 1 && ?has_rqa = 1, "both reported"^^xsd:string,
            IF(?has_rq = 1 && (!BOUND(?has_rqa) || ?has_rqa != 1), "only research question reported"^^xsd:string,
                IF((!BOUND(?has_rq) || ?has_rq != 1) && ?has_rqa = 1, "only research question answer reported"^^xsd:string,
                    "neither reported"^^xsd:string
                )
            )
        ) AS ?reporting_case
    )
}
GROUP BY ?year ?reporting_case
ORDER BY ?year ?reporting_case

SELECT DISTINCT ?naturalLanguage WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_type ?dtype .
  ?dtype pgmr:rigor_of_data_format ?rigor .
  ?rigor rdfs:label ?rigorLabel .
  FILTER(CONTAINS(LCASE(STR(?rigorLabel)), "strict"))
  ?dtype pgmr:natural_language ?lang .
  OPTIONAL { ?lang rdfs:label ?langLabel . }
  BIND(COALESCE(?langLabel, STR(?lang)) AS ?naturalLanguage)
}

SELECT DISTINCT ?licenseTypeText WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:implemented_approach ?approach .
  ?approach pgmr:release ?release ;
           pgmr:license_type ?licenseType .
  ?release pgmr:release_location_type ?locationType .
  ?locationType rdfs:label ?locationTypeLabel .
  FILTER(CONTAINS(LCASE(STR(?locationTypeLabel)), "repository") || CONTAINS(LCASE(STR(?locationTypeLabel)), "github"))
  OPTIONAL { ?licenseType rdfs:label ?licenseTypeLabel . }
  BIND(COALESCE(?licenseTypeLabel, STR(?licenseType)) AS ?licenseTypeText)
}

SELECT DISTINCT ?metric ?metricLabel WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:evaluation ?evaluation .
  ?evaluation pgmr:evaluation_metric ?metric ;
    pgmr:validation_procedure ?validationProcedure .
  ?validationProcedure rdfs:label ?validationProcedureLabel .
  FILTER(LCASE(STR(?validationProcedureLabel)) = LCASE('cross-validation'))
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
}

SELECT DISTINCT (COALESCE(?licenseTypeLabel, STR(?licenseType)) AS ?licenseTypeValue) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:implemented_approach ?approach .
  ?approach pgmr:release ?release .
  ?release pgmr:url ?url .
  FILTER(CONTAINS(LCASE(STR(?url)), 'github'))
  ?approach pgmr:license_type ?licenseType .
  OPTIONAL { ?licenseType rdfs:label ?licenseTypeLabel . }
}

SELECT DISTINCT ?numSources WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_source ?source .
  ?source pgmr:nlp_data_source_domain ?domain .
  ?domain rdfs:label ?domainLabel .
  FILTER(LCASE(STR(?domainLabel)) = LCASE('information systems'))
  ?source pgmr:number_of_data_sources ?numSources .
}

SELECT DISTINCT ?productionTime WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_source ?source .
  ?source pgmr:nlp_data_source_domain ?domain .
  ?domain rdfs:label ?domainLabel .
  FILTER(LCASE(STR(?domainLabel)) = LCASE('automotive'))
  ?dataset pgmr:nlp_data_production_time ?productionTime .
}

SELECT DISTINCT ?sourceType ?sourceTypeLabel WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_source ?source .
  ?source pgmr:number_of_data_sources ?numSources .
  FILTER(?numSources > 1)
  ?source pgmr:nlp_data_source_type ?sourceType .
  OPTIONAL { ?sourceType rdfs:label ?sourceTypeLabel . }
}

SELECT DISTINCT (COALESCE(?establishmentLabel, STR(?establishment)) AS ?establishmentValue) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:annotation_process ?annotationProcess .
  ?annotationProcess pgmr:annotator ?annotator ;
    pgmr:annotation_scheme ?annotationScheme .
  ?annotator pgmr:number_of_annotators ?numAnnotators .
  FILTER(?numAnnotators = 2)
  ?annotationScheme pgmr:scheme_establishement ?establishment .
  OPTIONAL { ?establishment rdfs:label ?establishmentLabel . }
}

SELECT DISTINCT ?releaseFormat ?releaseFormatLabel WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:implemented_approach ?approach .
  ?approach pgmr:release ?release .
  ?release pgmr:url ?url ;
    pgmr:release_format ?releaseFormat .
  FILTER(CONTAINS(LCASE(STR(?url)), 'github'))
  OPTIONAL { ?releaseFormat rdfs:label ?releaseFormatLabel . }
}

SELECT (COUNT(DISTINCT ?contribution) AS ?numContributions) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:evaluation ?evaluation .
  ?evaluation pgmr:baseline_comparison ?baselineComparison ;
    pgmr:evaluation_metric ?metric .
  ?metric rdfs:label ?metricLabel .
  FILTER(LCASE(STR(?metricLabel)) = LCASE('accuracy'))
}

SELECT DISTINCT ?documentationType ?documentationTypeLabel WHERE {
