  OPTIONAL { ?documentationType rdfs:label ?documentationTypeLabel . }
}

SELECT DISTINCT (COALESCE(?experienceLabel, STR(?experience)) AS ?experienceValue) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset ;
    pgmr:annotation_process ?annotationProcess .
  ?dataset pgmr:nlp_data_source ?source .
  ?source pgmr:nlp_data_source_domain ?domain .
  ?domain rdfs:label ?domainLabel .
  FILTER(LCASE(STR(?domainLabel)) = LCASE('information systems'))
  ?annotationProcess pgmr:annotator ?annotator .
  ?annotator pgmr:level_of_application_domain_experience ?experience .
  OPTIONAL { ?experience rdfs:label ?experienceLabel . }
}

SELECT (COUNT(DISTINCT ?contribution) AS ?numContributions) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_type ?dataType .
  ?dataType pgmr:natural_language ?naturalLanguage ;
    pgmr:nlp_data_format ?dataFormat .
  ?naturalLanguage rdfs:label ?naturalLanguageLabel .
  FILTER(LCASE(STR(?naturalLanguageLabel)) = LCASE('english'))
  ?dataFormat rdfs:label ?dataFormatLabel .
  FILTER(CONTAINS(LCASE(STR(?dataFormatLabel)), 'token-level'))
}

SELECT DISTINCT (COALESCE(?dependencyLabel, STR(?dependency)) AS ?dependencyValue) WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:implemented_approach ?approach .
  ?approach pgmr:release ?release ;
    pgmr:dependency ?dependency .
  ?release pgmr:url ?url .
  FILTER(CONTAINS(LCASE(STR(?url)), 'github'))
  OPTIONAL { ?dependency rdfs:label ?dependencyLabel . }
}

SELECT DISTINCT ?reliabilityMetric WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:annotation_process ?annotationProcess .
  ?annotationProcess pgmr:annotator_agreement ?agreement .
  ?agreement pgmr:conflict_resolution ?resolution .
  ?resolution rdfs:label ?resolutionLabel .
  FILTER(CONTAINS(LCASE(STR(?resolutionLabel)), "discussion") || CONTAINS(LCASE(STR(?resolutionLabel)), "consensus"))
  ?agreement pgmr:intercoder_reliability_metric ?metric .
  OPTIONAL { ?metric rdfs:label ?metricLabel . }
  BIND(COALESCE(?metricLabel, STR(?metric)) AS ?reliabilityMetric)
}

SELECT DISTINCT ?domain ?domainLabel WHERE {
  ?paper pgmr:has_contribution ?contribution .
  ?contribution a pgmrc:nlp4re_contribution ;
    pgmr:nlp_dataset ?dataset .
  ?dataset pgmr:nlp_data_source ?source .
  ?source pgmr:number_of_data_sources ?numSources ;
          pgmr:nlp_data_source_domain ?domain .
  OPTIONAL { ?domain rdfs:label ?domainLabel . }
  FILTER(xsd:integer(?numSources) >= 2)
}
